import{_ as n,o as s,c as e,a4 as t}from"./chunks/framework._in6GHBg.js";const g=JSON.parse('{"title":"写作套路","description":"","frontmatter":{},"headers":[],"relativePath":"english/Eng-Review-Routine-005-写作套路-V1.0-20260405.md","filePath":"english/Eng-Review-Routine-005-写作套路-V1.0-20260405.md"}'),l={name:"english/Eng-Review-Routine-005-写作套路-V1.0-20260405.md"};function i(p,a,o,r,d,c){return s(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="写作套路" tabindex="-1">写作套路 <a class="header-anchor" href="#写作套路" aria-label="Permalink to &quot;写作套路&quot;">​</a></h1><p><strong>结构清晰→内容充实→语言高级</strong></p><hr><h2 id="一、题型识别" tabindex="-1">一、题型识别 <a class="header-anchor" href="#一、题型识别" aria-label="Permalink to &quot;一、题型识别&quot;">​</a></h2><h3 id="高考写作题型" tabindex="-1">高考写作题型 <a class="header-anchor" href="#高考写作题型" aria-label="Permalink to &quot;高考写作题型&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">题型</th><th style="text-align:center;">分值</th><th style="text-align:center;">字数</th><th style="text-align:left;">特点</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>应用文</strong></td><td style="text-align:center;">15分</td><td style="text-align:center;">80-100词</td><td style="text-align:left;">书信、通知、演讲稿等</td></tr><tr><td style="text-align:center;"><strong>读后续写</strong></td><td style="text-align:center;">20分</td><td style="text-align:center;">150词</td><td style="text-align:left;">续写故事，情节合理</td></tr><tr><td style="text-align:center;"><strong>概要写作</strong></td><td style="text-align:center;">20分</td><td style="text-align:center;">60词</td><td style="text-align:left;">概括要点</td></tr></tbody></table><hr><h2 id="二、应用文写作" tabindex="-1">二、应用文写作 <a class="header-anchor" href="#二、应用文写作" aria-label="Permalink to &quot;二、应用文写作&quot;">​</a></h2><h3 id="_2-1-书信类" tabindex="-1">2.1 书信类 <a class="header-anchor" href="#_2-1-书信类" aria-label="Permalink to &quot;2.1 书信类&quot;">​</a></h3><h4 id="建议信" tabindex="-1">建议信 <a class="header-anchor" href="#建议信" aria-label="Permalink to &quot;建议信&quot;">​</a></h4><p><strong>结构</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>开头：表明写信目的</span></span>
<span class="line"><span>主体：具体建议（分点）</span></span>
<span class="line"><span>结尾：希望采纳，期待回复</span></span></code></pre></div><p><strong>模板</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Dear [Name],</span></span>
<span class="line"><span></span></span>
<span class="line"><span>I am writing to offer some suggestions on [topic].</span></span>
<span class="line"><span></span></span>
<span class="line"><span>First of all, I suggest that you [suggestion 1]. This will help you [benefit 1]. </span></span>
<span class="line"><span></span></span>
<span class="line"><span>Besides, it would be a good idea to [suggestion 2]. By doing so, you can [benefit 2].</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Finally, I recommend that you [suggestion 3]. I am sure this will [benefit 3].</span></span>
<span class="line"><span></span></span>
<span class="line"><span>I hope you will find these suggestions helpful. Looking forward to your reply.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Yours sincerely,</span></span>
<span class="line"><span>Li Hua</span></span></code></pre></div><p><strong>常用句型</strong>：</p><ul><li>I am writing to offer some suggestions on...</li><li>I suggest that you (should)...</li><li>It would be a good idea to...</li><li>I recommend that...</li><li>I hope you will find these suggestions helpful.</li></ul><hr><h4 id="申请信" tabindex="-1">申请信 <a class="header-anchor" href="#申请信" aria-label="Permalink to &quot;申请信&quot;">​</a></h4><p><strong>结构</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>开头：自我介绍+申请目的</span></span>
<span class="line"><span>主体：申请理由（能力、经验、动机）</span></span>
<span class="line"><span>结尾：表达期待，附上联系方式</span></span></code></pre></div><p><strong>模板</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Dear Sir/Madam,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>I am Li Hua, a student from [school]. I am writing to apply for [position/opportunity].</span></span>
<span class="line"><span></span></span>
<span class="line"><span>I believe I am qualified for this position for the following reasons. First, I have [ability/experience 1]. Second, I am good at [ability 2]. Most importantly, I am enthusiastic about [topic] and eager to [goal].</span></span>
<span class="line"><span></span></span>
<span class="line"><span>I would appreciate it if you could give me this opportunity. Please contact me at [phone number] or [email].</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Looking forward to your reply.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Yours sincerely,</span></span>
<span class="line"><span>Li Hua</span></span></code></pre></div><p><strong>常用句型</strong>：</p><ul><li>I am writing to apply for...</li><li>I believe I am qualified for...</li><li>I would appreciate it if you could...</li><li>Please contact me at...</li></ul><hr><h4 id="感谢信" tabindex="-1">感谢信 <a class="header-anchor" href="#感谢信" aria-label="Permalink to &quot;感谢信&quot;">​</a></h4><p><strong>模板</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Dear [Name],</span></span>
<span class="line"><span></span></span>
<span class="line"><span>I am writing to express my sincere gratitude for [what you did].</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Your help/kindness has [impact]. Without your help, I would not have been able to [achievement]. I was deeply touched by [specific detail].</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Thanks again for your generosity. I hope I can do something for you in return.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Yours sincerely,</span></span>
<span class="line"><span>Li Hua</span></span></code></pre></div><hr><h3 id="_2-2-通知-演讲稿" tabindex="-1">2.2 通知/演讲稿 <a class="header-anchor" href="#_2-2-通知-演讲稿" aria-label="Permalink to &quot;2.2 通知/演讲稿&quot;">​</a></h3><h4 id="通知" tabindex="-1">通知 <a class="header-anchor" href="#通知" aria-label="Permalink to &quot;通知&quot;">​</a></h4><p><strong>格式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Notice</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[内容：时间、地点、事件、要求]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[落款]</span></span>
<span class="line"><span>[日期]</span></span></code></pre></div><p><strong>模板</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Notice</span></span>
<span class="line"><span></span></span>
<span class="line"><span>A [event] will be held [time] at [place]. All [people] are welcome to attend.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>The event will include [activities]. Please [requirements].</span></span>
<span class="line"><span></span></span>
<span class="line"><span>For more information, please contact [contact person] at [phone number].</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[Organization]</span></span>
<span class="line"><span>[Date]</span></span></code></pre></div><hr><h4 id="演讲稿" tabindex="-1">演讲稿 <a class="header-anchor" href="#演讲稿" aria-label="Permalink to &quot;演讲稿&quot;">​</a></h4><p><strong>结构</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>开头：问候+引入话题</span></span>
<span class="line"><span>主体：论点+论据</span></span>
<span class="line"><span>结尾：总结+感谢</span></span></code></pre></div><p><strong>模板</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Dear teachers and fellow students,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>It is my great honor to stand here and give a speech on [topic].</span></span>
<span class="line"><span></span></span>
<span class="line"><span>As we all know, [background]. However, [problem]. Therefore, [your opinion].</span></span>
<span class="line"><span></span></span>
<span class="line"><span>First, [argument 1]. Second, [argument 2]. Last but not least, [argument 3].</span></span>
<span class="line"><span></span></span>
<span class="line"><span>In conclusion, [summary]. Let&#39;s [call to action].</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Thank you for listening!</span></span></code></pre></div><hr><h2 id="三、读后续写" tabindex="-1">三、读后续写 <a class="header-anchor" href="#三、读后续写" aria-label="Permalink to &quot;三、读后续写&quot;">​</a></h2><h3 id="_3-1-解题步骤" tabindex="-1">3.1 解题步骤 <a class="header-anchor" href="#_3-1-解题步骤" aria-label="Permalink to &quot;3.1 解题步骤&quot;">​</a></h3><ol><li><strong>读懂原文</strong>：把握人物、情节、冲突</li><li><strong>分析段落首句</strong>：确定续写方向</li><li><strong>构思情节</strong>：合理、连贯、有高潮</li><li><strong>写作</strong>：注意语言生动</li></ol><h3 id="_3-2-情节设计原则" tabindex="-1">3.2 情节设计原则 <a class="header-anchor" href="#_3-2-情节设计原则" aria-label="Permalink to &quot;3.2 情节设计原则&quot;">​</a></h3><ul><li><strong>合理</strong>：符合生活逻辑</li><li><strong>连贯</strong>：与原文衔接自然</li><li><strong>积极</strong>：传递正能量</li><li><strong>完整</strong>：有起因、经过、结果</li></ul><h3 id="_3-3-语言技巧" tabindex="-1">3.3 语言技巧 <a class="header-anchor" href="#_3-3-语言技巧" aria-label="Permalink to &quot;3.3 语言技巧&quot;">​</a></h3><p><strong>描写情感</strong>：</p><ul><li>Tears welled up in her eyes.</li><li>His heart sank.</li><li>A wave of relief washed over her.</li></ul><p><strong>描写动作</strong>：</p><ul><li>Without hesitation, he rushed to...</li><li>She froze, unable to move.</li></ul><p><strong>环境烘托</strong>：</p><ul><li>The wind howled outside.</li><li>The sun broke through the clouds.</li></ul><hr><h2 id="四、高分语言技巧" tabindex="-1">四、高分语言技巧 <a class="header-anchor" href="#四、高分语言技巧" aria-label="Permalink to &quot;四、高分语言技巧&quot;">​</a></h2><h3 id="_4-1-高级句型" tabindex="-1">4.1 高级句型 <a class="header-anchor" href="#_4-1-高级句型" aria-label="Permalink to &quot;4.1 高级句型&quot;">​</a></h3><p><strong>定语从句</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>As is known to all, reading is beneficial to us.</span></span>
<span class="line"><span>Those who read regularly tend to have better grades.</span></span></code></pre></div><p><strong>非谓语动词</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Faced with difficulties, we should never give up.</span></span>
<span class="line"><span>Having finished his homework, he went out to play.</span></span></code></pre></div><p><strong>倒装句</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Only in this way can we solve the problem.</span></span>
<span class="line"><span>Not only does he study hard, but he also helps others.</span></span></code></pre></div><p><strong>强调句</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>It is reading that broadens our horizons.</span></span></code></pre></div><p><strong>虚拟语气</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>If I were you, I would take this opportunity.</span></span>
<span class="line"><span>Without your help, I would have failed.</span></span></code></pre></div><h3 id="_4-2-高级词汇替换" tabindex="-1">4.2 高级词汇替换 <a class="header-anchor" href="#_4-2-高级词汇替换" aria-label="Permalink to &quot;4.2 高级词汇替换&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">普通词</th><th style="text-align:center;">高级词</th></tr></thead><tbody><tr><td style="text-align:center;">important</td><td style="text-align:center;">significant, essential, vital, crucial</td></tr><tr><td style="text-align:center;">good</td><td style="text-align:center;">beneficial, favorable, excellent</td></tr><tr><td style="text-align:center;">bad</td><td style="text-align:center;">harmful, unfavorable, negative</td></tr><tr><td style="text-align:center;">think</td><td style="text-align:center;">believe, consider, maintain, argue</td></tr><tr><td style="text-align:center;">very</td><td style="text-align:center;">extremely, remarkably, exceedingly</td></tr><tr><td style="text-align:center;">more and more</td><td style="text-align:center;">an increasing number of, increasingly</td></tr><tr><td style="text-align:center;">help</td><td style="text-align:center;">assist, contribute to, be beneficial to</td></tr><tr><td style="text-align:center;">use</td><td style="text-align:center;">utilize, make use of, take advantage of</td></tr><tr><td style="text-align:center;">want to</td><td style="text-align:center;">intend to, desire to, be eager to</td></tr><tr><td style="text-align:center;">because of</td><td style="text-align:center;">due to, owing to, thanks to</td></tr></tbody></table><h3 id="_4-3-过渡词" tabindex="-1">4.3 过渡词 <a class="header-anchor" href="#_4-3-过渡词" aria-label="Permalink to &quot;4.3 过渡词&quot;">​</a></h3><p><strong>递进</strong>：</p><ul><li>First, ... Second, ... Finally, ...</li><li>Besides, In addition, What&#39;s more, Furthermore</li></ul><p><strong>转折</strong>：</p><ul><li>However, Nevertheless, On the contrary, While</li></ul><p><strong>因果</strong>：</p><ul><li>Therefore, Thus, As a result, Consequently</li></ul><p><strong>举例</strong>：</p><ul><li>For example, For instance, Such as</li></ul><p><strong>总结</strong>：</p><ul><li>In conclusion, To sum up, All in all, In short</li></ul><hr><h2 id="五、检查清单" tabindex="-1">五、检查清单 <a class="header-anchor" href="#五、检查清单" aria-label="Permalink to &quot;五、检查清单&quot;">​</a></h2><h3 id="内容检查" tabindex="-1">内容检查 <a class="header-anchor" href="#内容检查" aria-label="Permalink to &quot;内容检查&quot;">​</a></h3><ul><li>[ ] 格式正确（书信有称呼落款）</li><li>[ ] 要点齐全</li><li>[ ] 逻辑清晰</li><li>[ ] 字数合适</li></ul><h3 id="语言检查" tabindex="-1">语言检查 <a class="header-anchor" href="#语言检查" aria-label="Permalink to &quot;语言检查&quot;">​</a></h3><ul><li>[ ] 时态一致</li><li>[ ] 主谓一致</li><li>[ ] 拼写正确</li><li>[ ] 标点正确</li></ul><h3 id="提升检查" tabindex="-1">提升检查 <a class="header-anchor" href="#提升检查" aria-label="Permalink to &quot;提升检查&quot;">​</a></h3><ul><li>[ ] 有高级句型（从句、非谓语、倒装）</li><li>[ ] 有高级词汇</li><li>[ ] 有过渡词</li><li>[ ] 书写工整</li></ul><hr><h2 id="六、常见错误" tabindex="-1">六、常见错误 <a class="header-anchor" href="#六、常见错误" aria-label="Permalink to &quot;六、常见错误&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">错误类型</th><th style="text-align:center;">错误示例</th><th style="text-align:center;">正确表达</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>时态混乱</strong></td><td style="text-align:center;">I go to school yesterday.</td><td style="text-align:center;">I went to school yesterday.</td></tr><tr><td style="text-align:center;"><strong>主谓不一致</strong></td><td style="text-align:center;">He don&#39;t like it.</td><td style="text-align:center;">He doesn&#39;t like it.</td></tr><tr><td style="text-align:center;"><strong>中式英语</strong></td><td style="text-align:center;">I very like it.</td><td style="text-align:center;">I like it very much.</td></tr><tr><td style="text-align:center;"><strong>词性错误</strong></td><td style="text-align:center;">It is importance.</td><td style="text-align:center;">It is important.</td></tr><tr><td style="text-align:center;"><strong>拼写错误</strong></td><td style="text-align:center;">enviroment</td><td style="text-align:center;">environment</td></tr></tbody></table><hr><p><strong>文档编号</strong>: Eng-Review-Routine-005<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>`,93)])])}const u=n(l,[["render",i]]);export{g as __pageData,u as default};
